const parentTs = $('Notify Slack').first().json.ts;
const parseResult = $('Parse LLM Response').first().json;
const sourcesObj = parseResult.sources_obj || {};

const items = [];
const icons = {
  Notion: '📚',
  Substack: '✉️',
  LinkedIn: '🔗'
};

for (const [app, titles] of Object.entries(sourcesObj)) {
  if (titles && titles.length > 0) {
    const lines = [`${icons[app] || '•'} *${app} Sources Used:*`];
    titles.forEach(title => {
      lines.push(`• ${title}`);
    });
    items.push({
      json: {
        thread_ts: parentTs,
        text: lines.join('\n')
      }
    });
  }
}

return items;

